export interface TailscaleDevice {
  id: string;
  /** The device's machine/host name. */
  name: string;
  /** The device's operating system (e.g. linux, macOS, iOS). */
  os: string;
  /** Whether the device is currently online, derived from how recently it was last seen. */
  online: boolean;
  /**
     * ISO timestamp of when the device was last seen, when known.
     * @nullable
     */
  lastSeen?: string | null;
  /** Whether the device offers an approved exit node (advertises and is allowed to route the default 0.0.0.0/0 route). */
  exitNode: boolean;
  /** The device's tailnet IP addresses (e.g. the 100.x.y.z CGNAT address and an IPv6 address), in the order Tailscale reports them. */
  addresses?: string[];
  /**
     * ISO timestamp of when the device's node key expires, or null when key expiry is disabled or no expiry is set.
     * @nullable
     */
  expires?: string | null;
  /** Whether key expiry has been disabled for this device (its node key never expires). */
  keyExpiryDisabled: boolean;
  /** Whether the device's node key is expiring within the warning window (or has already lapsed). Always false when key expiry is disabled. */
  keyExpiringSoon: boolean;
}

export interface TailscaleData {
  /** The tailnet name the devices belong to. */
  tailnet: string;
  /** Total number of devices in the tailnet. */
  deviceCount: number;
  /** Number of devices currently online. */
  onlineCount: number;
  /** Number of devices currently offline. */
  offlineCount: number;
  /** Number of online devices offering an approved exit node. */
  exitNodeCount: number;
  /** Number of devices whose node key is expiring soon (within the warning window) or has already lapsed. */
  expiringSoonCount: number;
  devices: TailscaleDevice[];
}

